const MyPromise = require('./myPromise');
let promise = new MyPromise((resolve, reject) => {
  // resolve('\u6210\u529F')
  reject('\u5931\u8D25');
});

promise.then(
  (value) => {
    console.log(value);
  },
  (reason) => {
    console.log(reason);
  },
);
