`,paraId:9},{value:"\u4F46\u662F\u5982\u679C n=100\uFF0Ck=50\uFF0C\u90A3\u6211\u4EEC\u5C31\u9700\u8981\u5199 50 \u4E2A for \u5FAA\u73AF\u5D4C\u5957\uFF0C\u80AF\u5B9A\u662F\u4E0D\u5408\u7406\u7684\uFF0C\u8FD9\u65F6\u5019\u6211\u4EEC\u5C31\u9700\u8981\u7528",paraId:10},{value:"\u56DE\u6EAF\u6CD5\u7684\u9012\u5F52",paraId:10},{value:"\u6765\u89E3\u51B3\u5D4C\u5957\u5C42\u6570\u7684\u95EE\u9898",paraId:10},{value:"\u7528\u6811\u5F62\u7ED3\u6784\u6765\u5206\u6790\uFF0C\u53EF\u4EE5\u53D1\u73B0 n \u76F8\u5F53\u4E8E\u6811\u7684\u5BBD\u5EA6\uFF0Ck \u76F8\u5F53\u4E8E\u6811\u7684\u6DF1\u5EA6",paraId:11},{value:`/**
 * @param {number} n
 * @param {number} k
 * @return {number[][]}
 */
var combine = function (n, k) {
  let result = [];
  let path = [];
  const combineHelper = (n, k, startIndex) => {
    if (path.length === k) {
      result.push(Array.from(path));
      return;
    }
    for (let i = startIndex; i <= n - (k - path.length) + 1; i++) {
      // for\u5FAA\u73AF\u65F6\uFF0C\u9009\u62E9\u7684\u8D77\u59CB\u4F4D\u7F6E\u4E4B\u540E\u7684\u5143\u7D20\u4E2A\u6570\u5982\u679C\u5DF2\u7ECF\u5C0F\u4E8Ek\uFF0C\u5C31\u53EF\u4EE5\u9002\u5F53\u4FEE\u526A\u4E86
      // \u4E5F\u5C31\u662Fi <= n - (k - path.length) + 1
      path.push(i); // \u4E0B\u6807\u4E5F\u662F\u503C
      combineHelper(n, k, i + 1);
      path.pop();
    }
  };
  combineHelper(n, k, 1); // \u56E0\u4E3A\u9898\u76EE\u533A\u95F4\u76F4\u63A5\u662F[1,n]\uFF0C\u5C31\u53EF\u4EE5\u76F4\u63A5\u4E0B\u6807\u4ECE1\u5F00\u59CB
  return result;
};
