\u7B80\u5355\u601D\u8DEF\uFF1A`,paraId:13},{value:"\u5148\u5217\u51FA\u8DDF i \u503C\u6709\u5173\u7684\u56E0\u7D20\uFF1Ak\u3001n\u3001i\u3001path.length\uFF0C\u5E76\u4E14\u770B\u660E\u663E\u7ED1\u5B9A\u7684\u56E0\u7D20\uFF1Ak \u4E0E path.length \u662F\u7ED1\u5B9A\u7684\uFF0C\u53EF\u4EE5\u76F4\u63A5\u7ED9\u51FA\u5173\u7CFB k-path.length",paraId:14},{value:"\u6240\u4EE5\u5176\u5B9E\u56E0\u7D20\u503C\u5C31\u4E24\u4E2A\uFF1Ak-path.length\u3001n",paraId:14},{value:"\u5217\u51FA\u57FA\u672C\u516C\u5F0F\uFF1Ai <= \uFF1F",paraId:14},{value:"\u76F4\u63A5\u5206\u6790\u56E0\u7D20\u503C\u4E0E i \u7684\u6B63\u8D1F\u5173\u7CFB\uFF0Cn \u8D8A\u5927\uFF0Ci \u4E5F\u5C31\u8303\u56F4\u8D8A\u5927\uFF1Bk-path.length \u8D8A\u5927\uFF0C\u4E5F\u5C31\u610F\u5473\u7740\u6240\u9700\u8981\u7684\u503C\u7684\u4E2A\u6570\u4E5F\u8D8A\u591A\uFF0Ci \u7684\u8303\u56F4\u503C\u5C31\u8D8A\u5C0F\uFF0C\u8FD9\u4E48\u7B80\u5355\u5206\u6790\u5C31\u53EF\u4EE5\u76F4\u63A5\u7ED9\u51FA\uFF1Ai <= - (k-path.length) + n",paraId:14},{value:"\u7136\u540E\u518D\u56FE\uFF0C\u9A8C\u8BC1\u516C\u5F0F\uFF0C\u53D1\u73B0\u4E0D\u5BF9\uFF0C\u603B\u662F\u5C11\u4E86\u4E2A 1\uFF0C\u7EE7\u7EED\u5206\u6790\uFF08\u56DE\u6EAF\u7B97\u6CD5\u770B\u4EE3\u7801\u968F\u60F3\u5F55\u7684\u5206\u6790\uFF0Cleetcode \u8BC4\u8BBA\u533A\u6709\uFF09",paraId:14},{value:"\u529B\u6263\u94FE\u63A5",paraId:15,tocIndex:3},{value:`/**
 * @param {string} digits
 * @return {string[]}
 */
var letterCombinations = function (digits) {
  if (!digits.length) return [];
  const res = [],
    path = [];
  const map = [
    '',
    '',
    'abc',
    'def',
    'ghi',
    'jkl',
    'mno',
    'pqrs',
    'tuv',
    'wxyz',
  ];

  function backtracking(arr, k, i) {
    if (path.length === k) {
      res.push(path.join(''));
      return;
    }
    for (const str of map[arr[i]]) {
      path.push(str);
      backtracking(arr, k, i + 1);
      path.pop();
    }
  }
  backtracking(digits, digits.length, 0);
  return res;
};
`,paraId:16,tocIndex:3},{value:"\u529B\u6263\u94FE\u63A5",paraId:17,tocIndex:4},{value:"\u6CE8\u610F\u5230\u9898\u76EE\u4E2D\u7684",paraId:18},{value:"\u65E0\u9650\u5236\u91CD\u590D\u88AB\u9009\u53D6",paraId:18},{value:"\uFF0C\u4F46\u662F\u6CA1\u6709 0 \uFF0C\u56E0\u4E3A\u4E0B\u9762\u6709\u63D0\u793A\uFF1A1 <= candidates[i] <= 200\u3002",paraId:18},{value:"\u672C\u9898\u548C 77.\u7EC4\u5408\u3001216.\u7EC4\u5408\u603B\u548C III \u7684\u533A\u522B\u662F\uFF1A\u672C\u9898\u6CA1\u6709\u6570\u91CF\u8981\u6C42\uFF0C\u53EF\u4EE5\u65E0\u9650\u91CD\u590D\uFF0C\u4F46\u662F\u6709\u603B\u548C\u7684\u9650\u5236\uFF0C\u6240\u4EE5\u95F4\u63A5\u7684\u4E5F\u662F\u6709\u4E2A\u6570\u7684\u9650\u5236\u3002",paraId:19},{value:`
