\u65B0\u589E\u4E09\u4E2A\u53D8\u91CF\uFF1A`,paraId:53},{value:"moved\uFF1A\u4EE3\u8868\u662F\u5426\u9700\u8981\u79FB\u52A8\u8282\u70B9",paraId:54},{value:"pos\uFF1A\u4EE3\u8868\u904D\u5386\u65E7\u7684\u4E00\u7EC4\u5B50\u8282\u70B9\u7684\u8FC7\u7A0B\u4E2D\u9047\u5230\u7684\u6700\u5927\u7D22\u5F15\u503C k",paraId:54},{value:"patched\uFF1A\u6570\u91CF\u6807\u8BC6\uFF0C\u4EE3\u8868\u5DF2\u7ECF\u66F4\u65B0\u8FC7\u7684\u8282\u70B9\u6570\u91CF\uFF0Cpatched \u503C\u5E94\u8BE5\u5C0F\u4E8E\u65B0\u7684\u4E00\u7EC4\u5B50\u8282\u70B9\u4E2D\u9700\u8981\u66F4\u65B0\u7684\u8282\u70B9\u6570\u91CF",paraId:54},{value:"\u5728\u7B2C\u4E8C\u4E2A for \u5FAA\u73AF\u4E2D\uFF0C\u6BD4\u8F83 moved \u548C pos \u4E24\u4E2A\u503C\u6765\u5224\u65AD\u662F\u5426\u9700\u8981\u79FB\u52A8\u3002",paraId:55},{value:`// 1.\u6784\u9020source\u6570\u7EC4
const count = newEnd - j + 1;
const source = new Array(count).fill(-1);

// 2.\u6784\u5EFA\u7D22\u5F15\u8868keyIndex
const keyIndex = {};
let newStart = j;
let oldStart = j;
for (let i = newStart; i <= newEnd; i++) {
  keyIndex[newChildren[i].key] = i;
}

// 3.\u5224\u65AD\u662F\u5426\u9700\u8981\u79FB\u52A8DOM
let patched = 0;
let moved = false;
let pos = 0;
for (let i = oldStart; i <= oldEnd; i++) {
  oldVNode = oldChildren[i];
  if (patched <= count) {
    const k = keyIndex[oldVNode.key];
    if (typeof k !== 'undefined') {
      newVNode = newChildren[i];
      patch(oldVNode, newVNode, container);
      patched++; // \u6BCF\u66F4\u65B0\u4E00\u4E2A\u8282\u70B9\uFF0C\u90FD\u5C06patched\u53D8\u91CF+1
      source[k - newStart] = i;
      if (k < pos) {
        moved = true;
      } else {
        pos = k;
      }
    } else {
      unmount(oldVNode);
    }
  } else {
    // \u5982\u679C\u66F4\u65B0\u8FC7\u7684\u8282\u70B9\u6570\u91CF\u5927\u4E8E\u9700\u8981\u66F4\u65B0\u7684\u8282\u70B9\u6570\u91CF\uFF0C\u5219\u5378\u8F7D\u591A\u4F59\u7684\u8282\u70B9
    unmount(oldVNode);
  }
}
