let i = 0;
i += 1;

// O(n)
for (let i = 0; i < n; i += 1) {
  console.log(i);
}

// O(1)+O(n)=O(n)
let i = 0;
i += 1;
for (let i = 0; i < n; i += 1) {
  console.log(i);
}

// O(n)*O(n)=O(n^2)
for (let i = 0; i < n; i += 1) {
  for (let j = 0; j < n; j += 1) {
    console.log(i, j);
  }
}

// O(logN)
let i = 1;
while (i < n) {
  console.log(i);
  i *= 2;
}
