const preorder = (root) => {
  if (!root) return [];
  const res = [];
  const stack = [root];
  while (stack.length) {
    const cur = stack.pop();
    console.log(cur.val);
    if (cur.right) {
      stack.push(cur.right);
    }
    if (cur.left) {
      stack.push(cur.left);
    }
  }
};
preorder(data);
