const inorder = (root) => {
  const stack = [];
  const res = [];
  while (root || stack.length) {
    while (root) {
      stack.push(root);
      root = root.left;
    }
    root = stack.pop(); // \u6CE8\u610F\u662F\u8D4B\u503C\u7ED9root
    console.log(root.val);
    root = root.right; // \u4E0D\u8981\u52A0 if(root.right)
  }
  return res;
};

inorder(data);
